const input = $input.first().json;
const query = input.query;
if (!query) return [{ json: { error: 'Parameter "query" is required.' } }];

const language = input.language || 'en';
const sortBy = input.sort_by || 'publishedAt';

// Fetch API key from template_credentials
const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.news-newsapi&cred_key=eq.newsapi_key&select=cred_value',
  headers: pgHeaders
});

if (!creds || creds.length === 0 || !creds[0].cred_value) {
  return [{ json: { error: 'NewsAPI key not configured. Use add_credential to set it up.' } }];
}

const apiKey = creds[0].cred_value;

const data = await helpers.httpRequest({
  method: 'GET',
  url: 'https://newsapi.org/v2/everything?q=' + encodeURIComponent(query)
    + '&language=' + language + '&sortBy=' + sortBy + '&pageSize=5',
  headers: { 'X-Api-Key': apiKey }
});

if (data.status !== 'ok') {
  return [{ json: { error: data.message || 'NewsAPI request failed.' } }];
}

let result = 'News for "' + query + '" (' + data.totalResults + ' total):\n\n';
for (const a of (data.articles || [])) {
  result += '- ' + a.title + '\n';
  result += '  ' + (a.description || '').substring(0, 150) + '\n';
  result += '  Source: ' + a.source.name + ' | ' + a.publishedAt.split('T')[0] + '\n';
  result += '  ' + a.url + '\n\n';
}

return [{ json: { result } }];
